const { app, Tray, Menu } = require('electron/main')
const { nativeImage } = require('electron/common')
const { doSomethingTs } = require('./dist/index')

let tray = null

app.whenReady().then(() => {
    const red = nativeImage.createFromDataURL('data:image/png;base64,')
    const green = nativeImage.createFromDataURL('data:image/png;base64,')

    tray = new Tray(red)

    const contextMenu = Menu.buildFromTemplate([
        {
      label: 'Toggle Icon',
      type: 'checkbox',
      click: ({ checked }) => {
        checked ? tray.setImage(green) : tray.setImage(red)
      }
    }
    ])

    tray.setContextMenu(contextMenu)
})

doSomethingTs()